+// ============================================================================
+// Phase Execution
+// ============================================================================
+
+/**
+ * Run all three phases of the sweep.
+ */
+async function runSweepPhases(
+  sessionId: string,
+  repos: FleetRepo[],
+  config: SweepConfig,
+): Promise<void> {
+  const correlationId = getCorrelationId();
+
+  try {
+    // Update to running
+    await db
+      .update(agentSweepSessions)
+      .set({
+        status: "running",
+        startedAt: new Date(),
+        currentPhase: "phase1_analysis",
+        updatedAt: new Date(),
+      })
+      .where(eq(agentSweepSessions.id, sessionId));
+
+    getHub().publish(
+      fleetChannel,
+      "fleet.sweep_started",
+      { sessionId },
+      { correlationId },
+    );
+
+    // Phase 1: Analysis
+    await runPhase1Analysis(sessionId, repos, config);
+
+    // Phase 2: Planning
+    await runPhase2Planning(sessionId, repos, config);
+
+    // Phase 3: Execution (if not dry run)
+    if (!config.dryRun) {
+      await runPhase3Execution(sessionId, config);
+    }
+
+    // Complete
+    const session = await db
+      .select()
+      .from(agentSweepSessions)
+      .where(eq(agentSweepSessions.id, sessionId))
+      .get();
+
+    const startedAt = session?.startedAt;
+    const totalDurationMs = startedAt
+      ? Date.now() - new Date(startedAt).getTime()
+      : 0;
+
+    await db
+      .update(agentSweepSessions)
+      .set({
+        status: "completed",
+        completedAt: new Date(),
+        totalDurationMs,
+        updatedAt: new Date(),
+      })
+      .where(eq(agentSweepSessions.id, sessionId));
+
+    getHub().publish(
+      fleetChannel,
+      "fleet.sweep_completed",
+      { sessionId, totalDurationMs },
+      { correlationId },
+    );
+
+    logger.info({ correlationId, sessionId, totalDurationMs }, "Agent sweep completed");
+  } catch (error) {
+    const errorMessage = error instanceof Error ? error.message : String(error);
+
+    await db
+      .update(agentSweepSessions)
+      .set({
+        status: "failed",
+        updatedAt: new Date(),
+      })
+      .where(eq(agentSweepSessions.id, sessionId));
+
+    await logSweepEvent(sessionId, "error", "Sweep failed", { error: errorMessage });
+
+    getHub().publish(
+      fleetChannel,
+      "fleet.sweep_failed",
+      { sessionId, error: errorMessage },
+      { correlationId },
+    );
+
+    logger.error({ correlationId, sessionId, error }, "Agent sweep failed");
+    throw error;
+  }
+}
+
+/**
+ * Phase 1: Analysis - Scan repos for issues.
+ */
+async function runPhase1Analysis(
+  sessionId: string,
+  repos: FleetRepo[],
+  config: SweepConfig,
+): Promise<void> {
+  const correlationId = getCorrelationId();
+  await logSweepEvent(sessionId, "info", "Starting Phase 1: Analysis", undefined, {
+    phase: "phase1",
+  });
+
+  let analyzed = 0;
+  const timeout = config.phase1Timeout || 300;
+
+  for (const repo of repos) {
+    const startTime = Date.now();
+
+    try {
+      // Run ru agent-sweep --phase1
+      const proc = spawn(
+        [
+          "ru",
+          "agent-sweep",
+          "--phase",
+          "1",
+          "--json",
+          "--timeout",
+          String(timeout),
+          repo.fullName,
+        ],
+        { stdout: "pipe", stderr: "pipe" },
+      );
+
+      const stdout = await new Response(proc.stdout).text();
+      const exitCode = await proc.exited;
+
+      const duration = Date.now() - startTime;
+
+      if (exitCode === 0) {
+        let result: { findings?: unknown[] } = {};
+        try {
+          result = JSON.parse(stdout);
+        } catch {
+          // Ignore parse errors
+        }
+
+        await logSweepEvent(
+          sessionId,
+          "info",
+          `Analyzed ${repo.fullName}`,
+          {
+            duration_ms: duration,
+            findings: result.findings,
+          },
+          { phase: "phase1", repoId: repo.id, durationMs: duration },
+        );
+        analyzed++;
+      } else {
+        await logSweepEvent(
+          sessionId,
+          "warn",
+          `Analysis failed for ${repo.fullName}`,
+          { exitCode },
+          { phase: "phase1", repoId: repo.id },
+        );
+      }
+    } catch (error) {
+      await logSweepEvent(
+        sessionId,
+        "error",
+        `Analysis error for ${repo.fullName}`,
+        { error: error instanceof Error ? error.message : String(error) },
+        { phase: "phase1", repoId: repo.id },
+      );
+    }
+
+    // Update progress
+    await db
+      .update(agentSweepSessions)
+      .set({ reposAnalyzed: analyzed, updatedAt: new Date() })
+      .where(eq(agentSweepSessions.id, sessionId));
+
+    getHub().publish(
+      fleetChannel,
+      "fleet.sweep_progress",
+      { sessionId, phase: "phase1", analyzed, total: repos.length },
+      { correlationId },
+    );
+  }
+
+  await db
+    .update(agentSweepSessions)
+    .set({
+      currentPhase: "phase2_planning",
+      phase1CompletedAt: new Date(),
+      updatedAt: new Date(),
+    })
+    .where(eq(agentSweepSessions.id, sessionId));
+
+  await logSweepEvent(sessionId, "info", "Phase 1 completed", { analyzed }, {
+    phase: "phase1",
+  });
+}
+
+/**
+ * Phase 2: Planning - Generate action plans.
+ */
+async function runPhase2Planning(
+  sessionId: string,
+  repos: FleetRepo[],
+  config: SweepConfig,
+): Promise<void> {
+  const correlationId = getCorrelationId();
+  await logSweepEvent(sessionId, "info", "Starting Phase 2: Planning", undefined, {
+    phase: "phase2",
+  });
+
+  let planned = 0;
+  const timeout = config.phase2Timeout || 600;
+
+  for (const repo of repos) {
+    const startTime = Date.now();
+
+    try {
+      // Run ru agent-sweep --phase2
+      const proc = spawn(
+        [
+          "ru",
+          "agent-sweep",
+          "--phase",
+          "2",
+          "--json",
+          "--timeout",
+          String(timeout),
+          repo.fullName,
+        ],
+        { stdout: "pipe", stderr: "pipe" },
+      );
+
+      const stdout = await new Response(proc.stdout).text();
+      const exitCode = await proc.exited;
+
+      const duration = Date.now() - startTime;
+
+      if (exitCode === 0) {
+        let plan: { actions?: Array<{ type: string; destructive?: boolean }> } = {};
+        try {
+          plan = JSON.parse(stdout);
+        } catch {
+          // Ignore parse errors
+        }
+
+        const actionCounts = countActionsByType(plan);
+        const riskLevel = assessRiskLevel(plan);
+
+        // Store plan
+        const now = new Date();
+        const planRecord = {
+          id: generateId("plan_"),
+          sessionId,
+          repoId: repo.id,
+          repoFullName: repo.fullName,
+          planJson: JSON.stringify(plan),
+          planVersion: 1,
+          actionCount: plan.actions?.length || 0,
+          riskLevel,
+          commitActions: actionCounts.commit,
+          releaseActions: actionCounts.release,
+          branchActions: actionCounts.branch,
+          prActions: actionCounts.pr,
+          otherActions: actionCounts.other,
+          approvalStatus: config.autoApprove
+            ? ("auto_approved" as PlanApprovalStatus)
+            : ("pending" as PlanApprovalStatus),
+          createdAt: now,
+        };
+
+        await db.insert(agentSweepPlans).values(planRecord);
+        planned++;
+
+        // Publish plan created event
+        getHub().publish(
+          fleetChannel,
+          "fleet.plan_created",
+          {
+            sessionId,
+            planId: planRecord.id,
+            repoFullName: repo.fullName,
+            actionCount: planRecord.actionCount,
+            riskLevel,
+          },
+          { correlationId },
+        );
+
+        await logSweepEvent(
+          sessionId,
+          "info",
+          `Created plan for ${repo.fullName}`,
+          {
+            planId: planRecord.id,
+            actionCount: planRecord.actionCount,
+            riskLevel: planRecord.riskLevel,
+          },
+          { phase: "phase2", repoId: repo.id, planId: planRecord.id, durationMs: duration },
+        );
+      } else {
+        await logSweepEvent(
+          sessionId,
+          "warn",
+          `Planning failed for ${repo.fullName}`,
+          { exitCode },
+          { phase: "phase2", repoId: repo.id },
+        );
+      }
+    } catch (error) {
+      await logSweepEvent(
+        sessionId,
+        "error",
+        `Planning error for ${repo.fullName}`,
+        { error: error instanceof Error ? error.message : String(error) },
+        { phase: "phase2", repoId: repo.id },
+      );
+    }
+
+    // Update progress
+    await db
+      .update(agentSweepSessions)
+      .set({ reposPlanned: planned, updatedAt: new Date() })
+      .where(eq(agentSweepSessions.id, sessionId));
+
+    getHub().publish(
+      fleetChannel,
+      "fleet.sweep_progress",
+      { sessionId, phase: "phase2", planned, total: repos.length },
+      { correlationId },
+    );
+  }
+
+  await db
+    .update(agentSweepSessions)
+    .set({
+      currentPhase: "phase3_execution",
+      phase2CompletedAt: new Date(),
+      updatedAt: new Date(),
+    })
+    .where(eq(agentSweepSessions.id, sessionId));
+
+  await logSweepEvent(sessionId, "info", "Phase 2 completed", { planned }, {
+    phase: "phase2",
+  });
+}
+
+/**
+ * Phase 3: Execution - Execute approved plans.
+ */
+async function runPhase3Execution(
+  sessionId: string,
+  config: SweepConfig,
+): Promise<void> {
+  const correlationId = getCorrelationId();
+  await logSweepEvent(sessionId, "info", "Starting Phase 3: Execution", undefined, {
+    phase: "phase3",
+  });
+
+  // Get approved plans
+  const plans = await db
+    .select()
+    .from(agentSweepPlans)
+    .where(
+      and(
+        eq(agentSweepPlans.sessionId, sessionId),
+        inArray(agentSweepPlans.approvalStatus, ["approved", "auto_approved"]),
+      ),
+    );
+
+  let executed = 0;
+  let failed = 0;
+  const timeout = config.phase3Timeout || 300;
+
+  for (const plan of plans) {
+    const startTime = Date.now();
+
+    try {
+      // Update plan status
+      await db
+        .update(agentSweepPlans)
+        .set({ executionStatus: "running", updatedAt: new Date() })
+        .where(eq(agentSweepPlans.id, plan.id));
+
+      // Run ru agent-sweep --phase3
+      const proc = spawn(
+        [
+          "ru",
+          "agent-sweep",
+          "--phase",
+          "3",
+          "--json",
+          "--timeout",
+          String(timeout),
+          "--plan-file",
+          "-", // Read from stdin
+        ],
+        { stdin: "pipe", stdout: "pipe", stderr: "pipe" },
+      );
+
+      // Write plan to stdin
+      const writer = proc.stdin.getWriter();
+      await writer.write(new TextEncoder().encode(plan.planJson));
+      await writer.close();
+
+      const stdout = await new Response(proc.stdout).text();
+      const exitCode = await proc.exited;
+
+      const duration = Date.now() - startTime;
+
+      let result: unknown = {};
+      try {
+        result = JSON.parse(stdout);
+      } catch {
+        result = { error: stdout };
+      }
+
+      await db
+        .update(agentSweepPlans)
+        .set({
+          executionStatus: exitCode === 0 ? "completed" : "failed",
+          executedAt: new Date(),
+          executionResult: JSON.stringify(result),
+          updatedAt: new Date(),
+        })
+        .where(eq(agentSweepPlans.id, plan.id));
+
+      if (exitCode === 0) {
+        executed++;
+      } else {
+        failed++;
+      }
+
+      await logSweepEvent(
+        sessionId,
+        exitCode === 0 ? "info" : "error",
+        `Executed plan for ${plan.repoFullName}`,
+        {
+          planId: plan.id,
+          success: exitCode === 0,
+          duration_ms: duration,
+        },
+        { phase: "phase3", repoId: plan.repoId || undefined, planId: plan.id, durationMs: duration },
+      );
+    } catch (error) {
+      failed++;
+      await db
+        .update(agentSweepPlans)
+        .set({
+          executionStatus: "failed",
+          executionResult: JSON.stringify({
+            error: error instanceof Error ? error.message : String(error),
+          }),
+          updatedAt: new Date(),
+        })
+        .where(eq(agentSweepPlans.id, plan.id));
+
+      await logSweepEvent(
+        sessionId,
+        "error",
+        `Execution error for ${plan.repoFullName}`,
+        { error: error instanceof Error ? error.message : String(error) },
+        { phase: "phase3", repoId: plan.repoId || undefined, planId: plan.id },
+      );
+    }
+
+    // Update session progress
+    await db
+      .update(agentSweepSessions)
+      .set({
+        reposExecuted: executed,
+        reposFailed: failed,
+        updatedAt: new Date(),
+      })
+      .where(eq(agentSweepSessions.id, sessionId));
+
+    getHub().publish(
+      fleetChannel,
+      "fleet.sweep_progress",
+      { sessionId, phase: "phase3", executed, failed, total: plans.length },
+      { correlationId },
+    );
+  }
+
+  await db
+    .update(agentSweepSessions)
+    .set({ phase3CompletedAt: new Date(), updatedAt: new Date() })
+    .where(eq(agentSweepSessions.id, sessionId));
+
+  await logSweepEvent(sessionId, "info", "Phase 3 completed", { executed, failed }, {
+    phase: "phase3",
+  });
+}
