+    .select()
+    .from(agentSweepLogs)
+    .where(and(...conditions))
+    .orderBy(desc(agentSweepLogs.timestamp))
+    .limit(options?.limit || 100)
+    .offset(options?.offset || 0);
+
+  return {
+    logs: logs as SweepLog[],
+    total: totalResult?.count || 0,
+  };
+}

